export default function Scene({ isBlizzard = false, onThunder, avatarRef, avatarFallKey = 0 }) {
  const [flashCount, setFlashCount] = useState(0)
  const timerRef = useRef(null)

  useEffect(() => {
    const clear = () => { if (timerRef.current) clearTimeout(timerRef.current) }
    if (!isBlizzard) { clear(); return }

    const schedule = (delay) => {
      timerRef.current = setTimeout(() => {
        setFlashCount(c => c + 1)
        if (onThunder) setTimeout(onThunder, 140)
        schedule(3500 + Math.random() * 5500)
      }, delay)
    }
    schedule(600 + Math.random() * 800)
    return clear
  }, [isBlizzard, onThunder])

  return (
    <>
      {/* Sky gradient */}
      <div
        aria-hidden="true"
        style={{
          position: 'absolute', inset: 0, zIndex: 0, pointerEvents: 'none',
          background: isBlizzard
            ? 'linear-gradient(to bottom, #8AAABB 0%, #B4C8D4 100%)'
            : 'linear-gradient(to bottom, #C8DCE8 0%, #E8F4F8 100%)',
          transition: 'background 0.8s ease',
        }}
      />

      {/* Sun glow — hidden in blizzard */}
      <div
        aria-hidden="true"
        style={{
          position: 'absolute',
          top: '-10%',
          right: '-10%',
          width: '55%',
          height: '70%',
          borderRadius: '50%',
          background: 'radial-gradient(ellipse at top right, rgba(255,228,120,0.32) 0%, rgba(255,210,80,0.10) 40%, transparent 70%)',
          zIndex: 1,
          pointerEvents: 'none',
          opacity: isBlizzard ? 0 : 1,
          transition: 'opacity 0.8s ease',
        }}
      />

      {/* New illustration — lower 55%, sits above snow base */}
      <img
        src={illustrationSvg}
        aria-hidden="true"
        alt=""
        style={{
          position: 'absolute',
          bottom: '10%',
          left: 0,
          width: '100%',
          height: '72%',
          objectFit: 'contain',
          objectPosition: 'bottom center',
          zIndex: 1,
          pointerEvents: 'none',
        }}
      />

      {/* Gondola */}
      <Gondola />

      {/* Snow ground — downhill slope, high-left to low-right */}
      <svg
        aria-hidden="true"
        style={{ position: 'absolute', bottom: 0, left: 0, width: '100%', height: '18%', zIndex: 2, pointerEvents: 'none' }}
        viewBox="0 0 1440 198"
        preserveAspectRatio="none"
      >
        <defs>
          <linearGradient id="snowBase" x1="0" y1="0" x2="1" y2="0.3">
            <stop offset="0%"  stopColor="#EEF6FA" />
            <stop offset="100%" stopColor="#E4F0F6" />
          </linearGradient>
        </defs>
        {/* Diagonal slope — rises on the left, descends to the right */}
        <path d="M0,8 Q360,22 720,52 Q1080,80 1440,104 L1440,198 L0,198 Z" fill="url(#snowBase)" />
        {/* Ski-track speed lines following the slope angle */}
        {[120, 300, 500, 680, 880, 1060, 1240, 1400].map((x, i) => {
          const baseY = 14 + (x / 1440) * 98
          return (
            <g key={x} opacity="0.18">
              <line x1={x}      y1={baseY + 14} x2={x + 38} y2={baseY + 30} stroke="#2A4A5A" strokeWidth="1.4" strokeLinecap="round" />
              <line x1={x + 16} y1={baseY +  8} x2={x + 54} y2={baseY + 24} stroke="#2A4A5A" strokeWidth="1.4" strokeLinecap="round" />
            </g>
          )
        })}
      </svg>

      {/* Clouds */}
      {CLOUDS.map((c, i) => <Cloud key={i} {...c} isBlizzard={isBlizzard} />)}

      {/* Avatar walking on snow */}
      <Avatar isBlizzard={isBlizzard} fallKey={avatarFallKey} outerRef={avatarRef} />

      {/* Blizzard vignette */}
      <div
        aria-hidden="true"
        style={{
          position: 'absolute', inset: 0, zIndex: 3, pointerEvents: 'none',
          background: 'radial-gradient(ellipse at center, transparent 35%, rgba(140,185,218,0.42) 100%)',
          opacity: isBlizzard ? 1 : 0,
          transition: 'opacity 0.6s ease',
        }}
      />

      {/* Lightning flash */}
      {isBlizzard && flashCount > 0 && (
        <div
          key={flashCount}
          aria-hidden="true"
          style={{
            position: 'absolute', inset: 0, zIndex: 9, pointerEvents: 'none',
            background: 'rgba(235, 245, 255, 0.88)',
            animation: 'lightningFlash 0.38s ease-out forwards',
          }}
        />
      )}

      {/* Snow particles */}
      {(isBlizzard
        ? Array.from({ length: 40 }, (_, i) => ({
            id: `b${i}`,
            left: (i * 2.5 + 1) % 100,
            size: 2 + (i % 4) * 0.85,
            duration: 1.4 + (i % 4) * 0.55,
            delay: (i * 0.14) % 4,
            opacity: 0.68 + (i % 3) * 0.12,
            anim: 'blizzardFall',
          }))
        : SNOWFLAKES.map(f => ({ ...f, anim: 'snowfall' }))
      ).map(f => (
        <div
          key={f.id}
          aria-hidden="true"
          style={{
            position: 'absolute',
            left: `${f.left}%`,
            top: '-10px',
            width:  `${f.size}px`,
            height: `${f.size}px`,
            borderRadius: '50%',
            background: 'white',
            animation: `${f.anim} ${f.duration}s linear ${f.delay}s infinite`,
            opacity: f.opacity,
            pointerEvents: 'none',
            zIndex: 4,
          }}
        />
      ))}
    </>
  )
}
